select visited_on , amount , average_amount from (select start_date , end_date , sum(Customer.amount) as amount , Customer.visited_on , ROUND(sum(Customer.amount) / 7 , 2) as average_amount from (select  start_date , end_date , sum(amount) as amount from (select c1.customer_id , c1.name , c1.visited_on as end_date ,c1.amount, c2.visited_on as start_date from Customer c1 join Customer c2 on c1.visited_on = c2.visited_on + interval 6 day) as res  group by start_date , end_date) as res1 join Customer on  Customer.visited_on between res1.start_date and res1.end_date group by start_date , end_date) as result order by visited_on

